<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">access = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;isMemberOf(&#39;team&#39;, &#39;engineering&#39;)&quot;</span></span>
